{"code": "import json, re

clin_key = 'var_functions.query_db:48'
mut_key = 'var_functions.query_db:36'

clin_result = locals()[clin_key]
mut_result = locals()[mut_key]

female_brca = json.load(open(clin_result)) if isinstance(clin_result, str) else clin_result
cdh1_mut = json.load(open(mut_result)) if isinstance(mut_result, str) else mut_result

patient_hist = {}
for r in female_brca:
    m = re.search(r'TCGA-[A-Z0-9]+-[A-Z0-9]+', r['Patient_description'])
    if m:
        patient_hist[m.group(0)] = r['histological_type']

cdh1_patients = set([m['ParticipantBarcode'] for m in cdh1_mut])

contingency = {}
for p, h in patient_hist.items():
    has_cdh1 = p in cdh1_patients
    if h not in contingency:
        contingency[h] = {'CDH1_mutated':0, 'CDH1_wildtype':0}
    if has_cdh1:
        contingency[h]['CDH1_mutated'] += 1
    else:
        contingency[h]['CDH1_wildtype'] += 1

filtered = {h:c for h,c in contingency.items() if sum(c.values()) > 10}

grand_total = sum([sum(c.values()) for c in filtered.values()])
col_mut = sum([c['CDH1_mutated'] for c in filtered.values()])
col_wt = sum([c['CDH1_wildtype'] for c in filtered.values()])

chi2 = 0
for h, c in filtered.items():
    row_total = sum(c.values())
    exp_mut = (row_total * col_mut) / grand_total
    exp_wt = (row_total * col_wt) / grand_total
    if exp_mut > 0:
        chi2 += ((c['CDH1_mutated'] - exp_mut) ** 2) / exp_mut
    if exp_wt > 0:
        chi2 += ((c['CDH1_wildtype'] - exp_wt) ** 2) / exp_wt

df = len(filtered) - 1
result = {'chi2': round(chi2, 4), 'df': df, 'table': filtered}
print('__RESULT__:')
print(json.dumps(result))"}

